import { describe, it, expect } from 'vitest';
import { analyzeConversionTopology } from './conversion-tracking-topology';

describe('ConversionTrackingTopology', () => {
  it('identifies continuous conversion fold when bule investment exceeds friction', () => {
    // 10 Bules invested, 5 units of friction -> it flows through (unbroken fold)
    const result = analyzeConversionTopology(10, 5);
    expect(result.isBounce).toBe(false);
    expect(result.ventSlam).toBe(0);
    expect(result.isUnbrokenFold).toBe(true);
  });

  it('detects a cart abandonment bounce when friction formally exceeds investment', () => {
    // 5 Bules invested, 15 units of friction -> mathematically bounces
    const result = analyzeConversionTopology(5, 15);
    expect(result.isBounce).toBe(true);
    expect(result.ventSlam).toBe(10);
    expect(result.isUnbrokenFold).toBe(false);
  });

  it('validates delta inputs accurately according to formal theorem conditions', () => {
    // 10 invested, 15 friction, explicit vent = 5
    const result = analyzeConversionTopology(10, 15, 5);
    expect(result.isBounce).toBe(true);
    expect(result.ventSlam).toBe(5);
  });

  it('throws an error when explicitly provided ventSlam breaks conservation geometry', () => {
    expect(() => {
      analyzeConversionTopology(10, 15, 6); // delta is 5, not 6
    }).toThrow('Topology bounds broken: ventSlam provided (6) does not match required delta (5)');
  });
});
